namespace Hexalith.Works.Architecture.Tests.FitnessTests;

internal static class RepositoryRoot
{
    public static string Locate()
    {
        DirectoryInfo? directory = new(AppContext.BaseDirectory);
        while (directory is not null)
        {
            if (File.Exists(Path.Combine(directory.FullName, "AGENTS.md"))
                && File.Exists(Path.Combine(directory.FullName, ".gitmodules")))
            {
                return directory.FullName;
            }

            directory = directory.Parent;
        }

        throw new InvalidOperationException($"Could not locate Hexalith.Works repository root above '{AppContext.BaseDirectory}'.");
    }

    public static string PathFromRoot(params string[] segments)
        => Path.Combine([Locate(), .. segments]);
}

using System.Xml.Linq;

using Shouldly;

namespace Hexalith.Works.Architecture.Tests.FitnessTests;

public sealed class ScaffoldGovernanceTests
{
    private static readonly string[] RequiredProjects =
    [
        "Hexalith.Works.Contracts",
        "Hexalith.Works.Server",
        "Hexalith.Works.Projections",
        "Hexalith.Works.Reactor",
        "Hexalith.Works.ServiceDefaults",
        "Hexalith.Works.AppHost",
        "Hexalith.Works.Testing",
    ];

    private static readonly string[] ForbiddenProjectFragments =
    [
        ".UI",
        ".Mcp",
        ".AdminPortal",
        ".ConsumerPortal",
        ".Security",
        ".Routing",
        ".Llm",
        ".LLM",
        ".CostGovernance",
        ".Email",
        ".Channel",
    ];

    [Fact]
    public void P0_ScaffoldContainsOnlyTheV1ProjectSet()
    {
        string root = RepositoryRoot.Locate();
        string[] projectFiles = Directory.GetFiles(root, "Hexalith.Works*.csproj", SearchOption.AllDirectories)
            .Where(path => !path.Contains($"{Path.DirectorySeparatorChar}_bmad-output{Path.DirectorySeparatorChar}", StringComparison.Ordinal))
            .ToArray();

        string[] projectNames = [.. projectFiles.Select(path => Path.GetFileNameWithoutExtension(path))];

        foreach (string requiredProject in RequiredProjects)
        {
            projectNames.ShouldContain(requiredProject, $"Story 1.1 requires '{requiredProject}' in the Works scaffold.");
        }

        string[] forbiddenProjects = [.. projectNames.Where(name => ForbiddenProjectFragments.Any(fragment => name.Contains(fragment, StringComparison.OrdinalIgnoreCase)))];
        forbiddenProjects.ShouldBeEmpty("Story 1.1 excludes UI, MCP, portal, security, routing, LLM, cost-governance, and production channel-adapter projects.");
    }

    [Fact]
    public void P0_ScaffoldUsesSlnxAndCentralPackageManagement()
    {
        string root = RepositoryRoot.Locate();

        File.Exists(Path.Combine(root, "Hexalith.Works.slnx")).ShouldBeTrue("Story 1.1 requires Hexalith.Works.slnx.");
        File.Exists(Path.Combine(root, "Hexalith.Works.sln")).ShouldBeFalse("Use .slnx, not .sln.");
        File.Exists(Path.Combine(root, "Directory.Packages.props")).ShouldBeTrue("Central package management must define package versions outside project files.");

        string[] projectFiles = Directory.GetFiles(root, "Hexalith.Works*.csproj", SearchOption.AllDirectories)
            .Where(path => !path.Contains($"{Path.DirectorySeparatorChar}_bmad-output{Path.DirectorySeparatorChar}", StringComparison.Ordinal))
            .ToArray();

        foreach (string projectFile in projectFiles)
        {
            XDocument project = XDocument.Load(projectFile);
            string[] inlineVersions = [.. project.Descendants()
                .Where(element => element.Name.LocalName == "PackageReference")
                .Where(element => element.Attribute("Version") is not null || element.Element("Version") is not null)
                .Select(element => element.Attribute("Include")?.Value ?? element.Attribute("Update")?.Value ?? projectFile)];

            inlineVersions.ShouldBeEmpty($"Package versions must be managed centrally, not inline in '{projectFile}'.");
        }
    }

    [Fact]
    public void P0_KernelProjectsStayInfrastructureFree()
    {
        string root = RepositoryRoot.Locate();
        string[] kernelProjects =
        [
            "Hexalith.Works.Contracts",
            "Hexalith.Works.Server",
            "Hexalith.Works.Projections",
        ];

        string[] forbiddenReferences =
        [
            "Dapr.Actors.AspNetCore",
            "Dapr.Client",
            "ModelContextProtocol",
            "Microsoft.AspNetCore.Components",
            "Microsoft.AspNetCore.OpenApi",
            "Swashbuckle",
            "OpenAI",
            "SemanticKernel",
        ];

        foreach (string project in kernelProjects)
        {
            string path = Path.Combine(root, "src", project, project + ".csproj");
            File.Exists(path).ShouldBeTrue($"Project file not found at '{path}'.");

            string text = File.ReadAllText(path);
            foreach (string forbidden in forbiddenReferences)
            {
                text.ShouldNotContain(forbidden, Case.Insensitive, $"{project} must remain kernel code and not reference adapter, Dapr runtime, UI, MCP, LLM, or OpenAPI packages.");
            }
        }
    }

    [Fact]
    public void P0_NestedSubmodulesRemainUninitialized()
    {
        string root = RepositoryRoot.Locate();
        string[] nestedGitDirectories = Directory.GetDirectories(root, ".git", SearchOption.AllDirectories)
            .Where(path => !string.Equals(path, Path.Combine(root, ".git"), StringComparison.Ordinal))
            .Where(path => path.Split(Path.DirectorySeparatorChar).Count(segment => segment.StartsWith("Hexalith.", StringComparison.Ordinal)) > 1)
            .ToArray();

        nestedGitDirectories.ShouldBeEmpty("Nested submodules inside root submodules must remain uninitialized; never run recursive submodule commands for this repository.");
    }
}

using Shouldly;

namespace Hexalith.Works.Architecture.Tests.FitnessTests;

public sealed class EventStoreApiSurfaceCharacterizationTests
{
    [Fact]
    public void P1_EventStoreExposesConcurrencyAndProjectionRebuildSurfacesNeededByWorks()
    {
        string eventStoreRoot = RepositoryRoot.PathFromRoot("Hexalith.EventStore");
        Directory.Exists(eventStoreRoot).ShouldBeTrue("The root Hexalith.EventStore submodule must be initialized non-recursively before Works implementation depends on it.");

        File.Exists(Path.Combine(eventStoreRoot, "src", "Hexalith.EventStore.Server", "Commands", "ConcurrencyConflictException.cs"))
            .ShouldBeTrue("Works claim/expected-version behavior needs an EventStore concurrency-conflict surface.");

        File.Exists(Path.Combine(eventStoreRoot, "src", "Hexalith.EventStore.Server", "Actors", "AggregateActor.cs"))
            .ShouldBeTrue("Works command handling depends on the EventStore aggregate actor pipeline.");

        File.Exists(Path.Combine(eventStoreRoot, "src", "Hexalith.EventStore.Contracts", "Streams", "ProjectionRebuildOperation.cs"))
            .ShouldBeTrue("Works projection rebuild planning depends on the EventStore rebuild operation contract.");

        File.Exists(Path.Combine(eventStoreRoot, "src", "Hexalith.EventStore.Contracts", "Streams", "ProjectionRebuildCheckpoint.cs"))
            .ShouldBeTrue("Works online rebuild planning depends on checkpointed projection rebuild support.");

        File.Exists(Path.Combine(eventStoreRoot, "src", "Hexalith.EventStore.Contracts", "Projections", "ProjectionChangedNotification.cs"))
            .ShouldBeTrue("Works read-model freshness depends on projection-change notification support.");
    }

    [Fact]
    public void P1_EventStoreExposesETagBackedProjectionInvalidationSurfaces()
    {
        string eventStoreRoot = RepositoryRoot.PathFromRoot("Hexalith.EventStore");

        string projectionWriteActor = File.ReadAllText(Path.Combine(eventStoreRoot, "src", "Hexalith.EventStore.Server", "Actors", "IProjectionWriteActor.cs"));
        projectionWriteActor.ShouldContain("UpdateProjectionAsync");
        projectionWriteActor.ShouldContain("ETag", Case.Insensitive);

        string etagActor = File.ReadAllText(Path.Combine(eventStoreRoot, "src", "Hexalith.EventStore.Server", "Actors", "IETagActor.cs"));
        etagActor.ShouldContain("GetCurrentETagAsync");
        etagActor.ShouldContain("RegenerateAsync");

        string notifier = File.ReadAllText(Path.Combine(eventStoreRoot, "src", "Hexalith.EventStore.Server", "Projections", "DaprProjectionChangeNotifier.cs"));
        notifier.ShouldContain("ProjectionChangedNotification");
        notifier.ShouldContain("RegenerateAsync");
    }
}
